// /frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

// Radar providers (same race as before)
const OWM_KEY = process.env.REACT_APP_OWM_KEY || import.meta?.env?.VITE_OWM_KEY || "";
const CENTER = [33.749, -84.388];
const ZOOM = 6;

// NEW: multiple base maps to avoid blank backgrounds
const BASES = {
  osm: {
    label: "OSM",
    url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",
    opts: { maxZoom: 19, opacity: 1, zIndex: 100, crossOrigin: true },
  },
  cartoDark: {
    label: "Carto Dark",
    url: "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
    opts: { subdomains: "abcd", maxZoom: 19, opacity: 1, zIndex: 100, crossOrigin: true },
  },
  esriGray: {
    label: "Esri Gray",
    url: "https://server.arcgisonline.com/ArcGIS/rest/services/Canvas/World_Light_Gray_Base/MapServer/tile/{z}/{y}/{x}",
    opts: { maxZoom: 16, opacity: 1, zIndex: 100, crossOrigin: true },
  },
  stamenTonerLite: {
    label: "Toner Lite",
    url: "https://stamen-tiles.a.ssl.fastly.net/toner-lite/{z}/{x}/{y}.png",
    opts: { maxZoom: 20, opacity: 1, zIndex: 100, crossOrigin: true },
  },
};

// Radar overlays
const PROVIDERS = {
  mesonet: {
    label: "Mesonet",
    url: "https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png",
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true },
  },
  rainviewer: { label: "RainViewer", dynamic: true },
  owm: {
    label: "OWM",
    url: OWM_KEY
      ? `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OWM_KEY}`
      : "",
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true },
  },
};

export default function Radar() {
  const mapRef = useRef(null);
  const baseLayerRef = useRef(null);
  const activeOverlayRef = useRef(null);

  const [loading, setLoading] = useState(true);
  const [errorText, setErrorText] = useState("");
  const [activeOverlay, setActiveOverlay] = useState("");
  const [manualOverlay, setManualOverlay] = useState(""); // '', 'mesonet', 'rainviewer', 'owm'
  const [base, setBase] = useState("osm"); // 'osm' | 'cartoDark' | 'esriGray' | 'stamenTonerLite'

  // init map
  useEffect(() => {
    if (mapRef.current) return;
    const map = L.map("radar-map", {
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
    }).setView(CENTER, ZOOM);
    mapRef.current = map;
    setTimeout(() => map.invalidateSize(), 0);
  }, []);

  // helper: set base safely
  const applyBase = (id) => {
    const map = mapRef.current;
    if (!map) return;
    const cfg = BASES[id] || BASES.osm;

    if (baseLayerRef.current) {
      try { map.removeLayer(baseLayerRef.current); } catch {}
      baseLayerRef.current = null;
    }
    const layer = L.tileLayer(cfg.url, cfg.opts)
      .on("load", () => {
        // once base loads at least one tile, we’re good
      })
      .on("tileerror", () => {
        // if a base fails, auto-fallback to OSM
        if (id !== "osm") applyBase("osm");
      })
      .addTo(map);

    baseLayerRef.current = layer;
  };

  // ensure a base is always present
  useEffect(() => {
    if (!mapRef.current) return;
    applyBase(base);
  }, [base]);

  // RainViewer dynamic layer builder
  const createRainviewerLayer = async () => {
    const meta = await fetch("https://api.rainviewer.com/public/weather-maps.json").then(r => r.json());
    const host = meta?.host || "";
    const frames = [...(meta?.radar?.past || []), ...(meta?.radar?.nowcast || [])];
    const last = frames.at(-1)?.time;
    if (!host || !last) throw new Error("No RainViewer frames");
    return L.tileLayer(`${host}/v2/radar/${last}/256/{z}/{x}/{y}.png`, {
      opacity: 0.85, zIndex: 500, crossOrigin: true
    });
  };

  // set active overlay
  const setActiveOverlayLayer = (layer, id) => {
    const map = mapRef.current;
    if (!map) return;
    if (activeOverlayRef.current) {
      try { map.removeLayer(activeOverlayRef.current); } catch {}
    }
    activeOverlayRef.current = layer.addTo(map);
    setActiveOverlay(id);
    setLoading(false);
    setErrorText("");
  };

  // AUTO overlay race (Mesonet → RainViewer → OWM)
  useEffect(() => {
    if (!mapRef.current || manualOverlay) return;

    let cancelled = false;
    setLoading(true);
    setErrorText("");
    setActiveOverlay("");

    const map = mapRef.current;
    const contestants = [];

    const win = (layer, id) => {
      if (cancelled) return;
      contestants.forEach(c => {
        if (c.layer && c.id !== id) {
          try { map.removeLayer(c.layer); } catch {}
        }
      });
      setActiveOverlayLayer(layer, id);
    };

    // Mesonet first
    const meso = L.tileLayer(PROVIDERS.mesonet.url, PROVIDERS.mesonet.opts)
      .on("load", () => win(meso, "mesonet"))
      .on("tileerror", () => {})
      .addTo(map);
    contestants.push({ id: "mesonet", layer: meso });

    // RainViewer
    (async () => {
      try {
        const rv = await createRainviewerLayer();
        if (cancelled) return;
        rv.on("load", () => win(rv, "rainviewer"))
          .on("tileerror", () => {});
        rv.addTo(map);
        contestants.push({ id: "rainviewer", layer: rv });
      } catch {}
    })();

    // OWM
    if (PROVIDERS.owm.url) {
      const owm = L.tileLayer(PROVIDERS.owm.url, PROVIDERS.owm.opts)
        .on("load", () => win(owm, "owm"))
        .on("tileerror", () => {});
      owm.addTo(map);
      contestants.push({ id: "owm", layer: owm });
    }

    const to = setTimeout(() => {
      if (!cancelled && !activeOverlayRef.current) {
        setLoading(false);
        setErrorText("Radar tiles didn’t load. Try switching provider.");
      }
    }, 5000);

    return () => {
      cancelled = true;
      clearTimeout(to);
      contestants.forEach(c => { try { map.removeLayer(c.layer); } catch {} });
    };
  }, [manualOverlay]);

  // MANUAL overlay switch
  useEffect(() => {
    if (!manualOverlay) return;
    const map = mapRef.current;
    if (!map) return;

    setLoading(true);
    setErrorText("");

    if (activeOverlayRef.current) {
      try { map.removeLayer(activeOverlayRef.current); } catch {}
      activeOverlayRef.current = null;
    }

    (async () => {
      try {
        if (manualOverlay === "mesonet") {
          const layer = L.tileLayer(PROVIDERS.mesonet.url, PROVIDERS.mesonet.opts)
            .on("load", () => setActiveOverlayLayer(layer, "mesonet"))
            .on("tileerror", () => setErrorText("Mesonet tiles failed to load."));
          layer.addTo(map);
        } else if (manualOverlay === "rainviewer") {
          const layer = await createRainviewerLayer();
          layer
            .on("load", () => setActiveOverlayLayer(layer, "rainviewer"))
            .on("tileerror", () => setErrorText("RainViewer tiles failed to load."));
          layer.addTo(map);
        } else if (manualOverlay === "owm") {
          if (!PROVIDERS.owm.url) {
            setLoading(false);
            return setErrorText("OWM key missing.");
          }
          const layer = L.tileLayer(PROVIDERS.owm.url, PROVIDERS.owm.opts)
            .on("load", () => setActiveOverlayLayer(layer, "owm"))
            .on("tileerror", () => setErrorText("OWM tiles failed to load."));
          layer.addTo(map);
        }
      } catch (e) {
        setLoading(false);
        setErrorText(e?.message || "Provider failed.");
      }
    })();
  }, [manualOverlay]);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      <div className="flex items-center justify-between px-3 py-2">
        <div className="text-sm opacity-80">
          Radar {activeOverlay ? `• ${PROVIDERS[activeOverlay]?.label || activeOverlay}` : ""}
        </div>
        <div className="flex items-center gap-2 text-xs">
          {/* Base switcher */}
          <div className="flex items-center gap-1">
            <span className="opacity-70">Base:</span>
            {Object.entries(BASES).map(([id, conf]) => (
              <button
                key={id}
                onClick={() => setBase(id)}
                className={`px-2 py-0.5 rounded ${base === id ? "bg-white/20" : "bg-white/10"}`}
              >
                {conf.label}
              </button>
            ))}
          </div>
          {/* Overlay switcher */}
          <div className="flex items-center gap-1 ml-3">
            <button
              className={`px-2 py-0.5 rounded ${manualOverlay === "" ? "bg-white/20" : "bg-white/10"}`}
              onClick={() => setManualOverlay("")}
              title="Auto"
            >
              Auto
            </button>
            <button
              className={`px-2 py-0.5 rounded ${manualOverlay === "mesonet" ? "bg-white/20" : "bg-white/10"}`}
              onClick={() => setManualOverlay("mesonet")}
            >
              Mesonet
            </button>
            <button
              className={`px-2 py-0.5 rounded ${manualOverlay === "rainviewer" ? "bg-white/20" : "bg-white/10"}`}
              onClick={() => setManualOverlay("rainviewer")}
            >
              RV
            </button>
            <button
              className={`px-2 py-0.5 rounded ${manualOverlay === "owm" ? "bg-white/20" : "bg-white/10"}`}
              onClick={() => setManualOverlay("owm")}
              disabled={!OWM_KEY}
              title={!OWM_KEY ? "Set REACT_APP_OWM_KEY / VITE_OWM_KEY" : "OpenWeather"}
            >
              OWM
            </button>
          </div>
        </div>
      </div>

      <div id="radar-map" style={{ height: 320, width: "100%" }} />

      {loading && (
        <div className="absolute inset-0 grid place-items-center">
          <div className="animate-spin h-6 w-6 rounded-full border-2 border-white/30 border-t-white" />
        </div>
      )}

      {!!errorText && !loading && (
        <div className="absolute bottom-2 left-2 right-2 text-xs px-2 py-1 rounded bg-black/70 ring-1 ring-white/10">
          {errorText}
        </div>
      )}

      {/* Tiny legend */}
      <div className="absolute bottom-3 left-3 text-[11px] rounded bg-black/60 px-2 py-1 ring-1 ring-white/10">
        <div className="font-medium mb-1">Precip Intensity</div>
        <div className="flex items-center gap-2">
          <span className="inline-block h-2 w-6 bg-yellow-400" /> Moderate
          <span className="inline-block h-2 w-6 bg-red-500" /> Heavy
          <span className="inline-block h-2 w-6 bg-blue-400" /> Snowy areas
        </div>
      </div>
    </div>
  );
}
